// Detect which AI brand the topic mentions and return its official
// YouTube channel + blog page. Mirrors publisher/media_sources/brand_detect.py
// — keep these two in sync when adding a new brand.
const topic = ($json.topic || '').toLowerCase();
const BRANDS = [
  { key: 'anthropic',   re: /(anthropic|claude)/,            channel_id: 'UCrDwWp7EBBv4NwvScIpBDOA', channel_handle: '@AnthropicAI',   blog: 'https://www.anthropic.com/news' },
  { key: 'openai',      re: /(openai|chatgpt|\bgpt[\- ]?\d|sora|dall[- ]?e)/, channel_id: 'UCXZCJLdBC09xxGZ6gcdrc6A', channel_handle: '@OpenAI', blog: 'https://openai.com/news' },
  { key: 'google',      re: /(gemini|google ai|deepmind|bard)/, channel_id: 'UCK8sQmJBp8GCxrOtXWBpyEA', channel_handle: '@Google', blog: 'https://blog.google/technology/ai/' },
  { key: 'microsoft',   re: /(copilot|microsoft ai|azure ai)/,  channel_id: 'UCQ-VqzfFLb9Z3wQzM2xKqHA', channel_handle: '@Microsoft', blog: 'https://blogs.microsoft.com/ai/' },
  { key: 'meta',        re: /(\bmeta ai\b|\bllama\b)/,           channel_id: 'UCbKWv2x9t6u8yZoB3KcPtnw', channel_handle: '@Meta',   blog: 'https://ai.meta.com/blog/' },
  { key: 'perplexity',  re: /(perplexity)/,                     channel_id: 'UC4_K2y4ZS8btnXyUDx48ItA', channel_handle: '@Perplexity', blog: 'https://www.perplexity.ai/hub/blog' },
  { key: 'notion',      re: /(notion ai|notion\.so)/,           channel_id: 'UCQ1xLP1Wd5p_0lD0NM7lwgQ', channel_handle: '@notion', blog: 'https://www.notion.so/blog' },
  { key: 'zapier',      re: /(zapier)/,                         channel_id: 'UCu6oMxOTwcSAtJVUyzL05dQ', channel_handle: '@zapier', blog: 'https://zapier.com/blog/' },
  { key: 'n8n',         re: /(\bn8n\b)/,                        channel_id: 'UCqAuOd3iZ_KFlbWeS_3Q1Mw', channel_handle: '@n8n-io',  blog: 'https://blog.n8n.io/' }
];
for (const b of BRANDS) {
  if (b.re.test(topic)) {
    return [{ json: { ...$json, brand: b.key, brand_channel_id: b.channel_id, brand_channel_handle: b.channel_handle, brand_blog: b.blog } }];
  }
}
return [{ json: { ...$json, brand: '', brand_channel_id: '', brand_channel_handle: '', brand_blog: '' } }];

// Stack candidates from all four search sources, score, pick best
// video URL + best preview-image URL. Mirrors the scoring logic in
// publisher/media_sources/scoring.py at a high level.
//
// Input shape: this Code node sits BEHIND a Merge node so $input.all()
// returns one item per branch.
//
// Candidates carry a `source` tag so downstream knows where they came
// from (we boost official-channel results +5).

function pickFirst(items, predicate) {
  for (const it of items) {
    const v = predicate(it);
    if (v) return v;
  }
  return '';
}

const items = $input.all();
let ytOfficial = null, ytGeneral = null, blog = null, ddg = null;
for (const it of items) {
  const j = it.json || {};
  // Distinguish branches by the labels we set on the prior node.
  if (j._branch === 'yt_official') ytOfficial = j;
  else if (j._branch === 'yt_general') ytGeneral = j;
  else if (j._branch === 'blog')  blog  = j;
  else if (j._branch === 'ddg')   ddg   = j;
}
// If the labels weren't set (n8n routing varies), fall back to positional.
if (!ytOfficial && items[0]) ytOfficial = items[0].json;
if (!ytGeneral  && items[1]) ytGeneral  = items[1].json;
if (!blog       && items[2]) blog       = items[2].json;
if (!ddg        && items[3]) ddg        = items[3].json;

// --- video candidates ---
let videoUrl = '', videoSource = '';
const officialItems = (ytOfficial && ytOfficial.items) || [];
if (officialItems.length && officialItems[0].id && officialItems[0].id.videoId) {
  videoUrl = `https://www.youtube.com/watch?v=${officialItems[0].id.videoId}`;
  videoSource = 'youtube_official';
}
if (!videoUrl) {
  const generalItems = (ytGeneral && ytGeneral.items) || [];
  for (const it of generalItems) {
    if (it.id && it.id.videoId) {
      videoUrl = `https://www.youtube.com/watch?v=${it.id.videoId}`;
      videoSource = 'youtube_general';
      break;
    }
  }
}

// --- image candidates ---
let imageUrl = '';
const html = (blog && blog.data) || (blog && blog.body) || '';
if (typeof html === 'string' && html.length) {
  const m = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i)
         || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i);
  if (m) imageUrl = m[1];
}
if (!imageUrl) {
  // DDG image fallback — its public JSON-ish endpoint embeds image urls.
  const ddgHtml = (ddg && ddg.data) || (ddg && ddg.body) || '';
  if (typeof ddgHtml === 'string') {
    const m = ddgHtml.match(/"image":\s*"(https:[^"]+)"/);
    if (m) imageUrl = m[1].replace(/\\\//g, '/');
  }
}
// As a last resort, take the YouTube video's thumbnail (always exists).
if (!imageUrl && officialItems[0] && officialItems[0].snippet) {
  imageUrl = (officialItems[0].snippet.thumbnails && officialItems[0].snippet.thumbnails.high && officialItems[0].snippet.thumbnails.high.url) || '';
}
if (!imageUrl) {
  const g = (ytGeneral && ytGeneral.items) || [];
  if (g[0] && g[0].snippet && g[0].snippet.thumbnails && g[0].snippet.thumbnails.high) {
    imageUrl = g[0].snippet.thumbnails.high.url;
  }
}

const base = $('Set - Extract Row Fields').first().json;
return [{
  json: {
    ...base,
    media_video_url: videoUrl,
    media_image_url: imageUrl,
    media_source: videoSource,
    media_status: videoUrl ? 'Found' : 'No source',
    media_found_at: new Date().toISOString()
  }
}];
